 var sub = e.parameter.sub;
 var Reason = '';
 var quit = false;
 app.getElementById('name').setText('**Please put in your name').setStyleAttribute("color", "red");
 //check to see that the data is correct
 if(name == '')
 {
    app.getElementById('name').setText('**Please put in your name').setStyleAttribute("color", "red");
    quit = true;
 }
  else app.getElementById('name').setText('**Required').setStyleAttribute("color", "blue");

 if (school == '--Please Select--')
 {
    app.getElementById('schoollist').setText('**Please select your school').setStyleAttribute("color", "red");
    quit = true;
 }
  else app.getElementById('schoollist').setText('**Required').setStyleAttribute("color", "blue");


 if (startdate == '') {
  app.getElementById('startdatelabel').setText('Please select a valid start date').setStyleAttribute("color", "red");
    quit = true;
 }
  else {
   var sdate = e.parameter.startdate;
   var tdate = new Date();
   sdate = sdate/60/60/24/1000;
   tdate =tdate/60/60/24/1000;
   var NumDays = sdate - tdate;

    if (NumDays < 3.3 && e.parameter.dateexplainbox == '') {
      quit = true;
      app.getElementById('startdatelabel').setText('**Please fill in reason for short notice of leave').setStyleAttribute("color", "red");
    }
    else if (NumDays < 3.3) {
      Reason = e.parameter.dateexplainbox + '   ';
    app.getElementById('startdatelabel').setText('**Required').setStyleAttribute("color", "blue");
    }
    else app.getElementById('startdatelabel').setText('**Required').setStyleAttribute("color", "blue");
    startdate = Utilities.formatDate(startdate, "GMT-05:00", "MM/dd/yyyy");   
  }

 if (enddate == '')
    app.getElementById('enddate').setText('').setStyleAttribute("color", "green");
 else
    enddate = Utilities.formatDate(enddate, "GMT-05:00", "MM/dd/yyyy");

 if (e.parameter.enddate) {
    sdate = startdate/60/60/24/1000;
    var edate = enddate/60/60/24/1000;
    if (enddate < startdate || enddate == startdate) {
    quit = true;
     app.getElementById('enddateerror').setText('Please select a date after the start date for your leave.').setStyleAttribute("color", "red");
    }
   else app.getElementById('enddateerror').setText('');
 }

 if (total == '' || e.parameter.outcheckr) {
    app.getElementById('outtotal').setText('**Please enter in a number for how many total days that you will be out').setStyleAttribute("color", "red");
    quit = true;
 }
  else app.getElementById('outtotal').setText('**Required').setStyleAttribute("color", "blue");


 if (leavetype == '--Please Select--'){
    app.getElementById('typeofleave').setText('**Please select a leave type').setStyleAttribute("color", "red");
    quit = true;
 }
  else app.getElementById('typeofleave').setText('**Required').setStyleAttribute("color", "blue");

 if (quit) {
    app.getElementById('process').setVisible(false);
    app.getElementById('error').setText('Please fix the problems marked above').setStyleAttribute("color", "red");
    return app;
 }

